/**
 * Quality Validator for HyDE-Lite
 *
 * Validates the quality of hypothetical answers generated by HyDE-Lite.
 * Ensures that generated text is suitable for embedding.
 *
 * @module smora/query-understanding/quality-validator
 */

/**
 * Quality validator for HyDE-Lite outputs
 */
export class QualityValidator {
  constructor(options = {}) {
    this.config = {
      minLength: options.minLength ?? 20,
      maxLength: options.maxLength ?? 1000,
      minWords: options.minWords ?? 5,
      maxRepetitionRatio: options.maxRepetitionRatio ?? 0.5,
      minUniqueRatio: options.minUniqueRatio ?? 0.3,
      enableRefusalDetection: options.enableRefusalDetection !== false,
      enableCoherenceCheck: options.enableCoherenceCheck ?? true,
      ...options
    };

    // Refusal patterns that indicate the model refused to answer
    this.refusalPatterns = [
      /I don't know/i,
      /I cannot answer/i,
      /I'm not sure/i,
      /I don't have (?:enough )?information/i,
      /I cannot provide/i,
      /I'm unable to/i,
      /I don't have access to/i,
      /Not enough information/i,
      /I'm sorry, I/i,
      /As an AI/i
    ];

    // Patterns that indicate errors or issues
    this.errorPatterns = [
      /error:/i,
      /failed to/i,
      /unable to process/i,
      /connection error/i,
      /timeout error/i
    ];

    this.metrics = {
      totalValidations: 0,
      passedValidations: 0,
      failedValidations: 0,
      failuresByReason: {}
    };
  }

  /**
   * Validate a hypothetical answer
   *
   * @param {string} hypothetical - The generated hypothetical answer
   * @param {string} query - The original query (for context)
   * @returns {Object} Validation result
   */
  validate(hypothetical, query = '') {
    this.metrics.totalValidations++;

    const result = {
      isValid: false,
      quality: 'unknown',
      score: 0,
      reason: null,
      details: {}
    };

    // Trim and check empty
    const text = hypothetical.trim();
    if (!text) {
      result.reason = 'empty';
      this._trackFailure('empty');
      return result;
    }

    // Length validation
    const lengthCheck = this._validateLength(text);
    result.details.length = lengthCheck;

    if (!lengthCheck.passed) {
      result.reason = lengthCheck.reason;
      this._trackFailure(lengthCheck.reason);
      return result;
    }

    // Refusal detection
    const refusalCheck = this._detectRefusal(text);
    result.details.refusal = refusalCheck;

    if (refusalCheck.isRefusal) {
      result.reason = 'refusal';
      this._trackFailure('refusal');
      return result;
    }

    // Error pattern detection
    const errorCheck = this._detectErrors(text);
    result.details.errors = errorCheck;

    if (errorCheck.hasErrors) {
      result.reason = 'error_patterns';
      this._trackFailure('error_patterns');
      return result;
    }

    // Repetition check
    const repetitionCheck = this._checkRepetition(text);
    result.details.repetition = repetitionCheck;

    if (!repetitionCheck.passed) {
      result.reason = 'excessive_repetition';
      this._trackFailure('repetition');
      return result;
    }

    // Coherence check (basic)
    const coherenceCheck = this._checkCoherence(text);
    result.details.coherence = coherenceCheck;

    if (!coherenceCheck.passed) {
      result.reason = 'incoherent';
      this._trackFailure('coherence');
      return result;
    }

    // All checks passed
    result.isValid = true;
    result.quality = this._calculateQuality(text, result.details);
    result.score = this._calculateScore(result.details);

    this.metrics.passedValidations++;
    return result;
  }

  /**
   * Validate text length
   * @private
   */
  _validateLength(text) {
    const length = text.length;
    const words = text.split(/\s+/).filter(w => w.length > 0);
    const wordCount = words.length;

    return {
      passed: length >= this.config.minLength && length <= this.config.maxLength &&
               wordCount >= this.config.minWords,
      length,
      wordCount,
      reason: length < this.config.minLength ? 'too_short' :
              length > this.config.maxLength ? 'too_long' :
              wordCount < this.config.minWords ? 'too_few_words' : null
    };
  }

  /**
   * Detect refusal patterns
   * @private
   */
  _detectRefusal(text) {
    if (!this.config.enableRefusalDetection) {
      return { isRefusal: false };
    }

    for (const pattern of this.refusalPatterns) {
      if (pattern.test(text)) {
        return {
          isRefusal: true,
          pattern: pattern.toString()
        };
      }
    }

    return { isRefusal: false };
  }

  /**
   * Detect error patterns
   * @private
   */
  _detectErrors(text) {
    for (const pattern of this.errorPatterns) {
      if (pattern.test(text)) {
        return {
          hasErrors: true,
          pattern: pattern.toString()
        };
      }
    }

    return { hasErrors: false };
  }

  /**
   * Check for excessive repetition
   * @private
   */
  _checkRepetition(text) {
    const words = text.toLowerCase().split(/\s+/);
    const uniqueWords = new Set(words);
    const uniqueRatio = uniqueWords.size / words.length;

    // Check for consecutive word repetition
    let consecutiveRepeats = 0;
    for (let i = 1; i < words.length; i++) {
      if (words[i] === words[i - 1]) {
        consecutiveRepeats++;
      }
    }

    // Check for repeated phrases (3+ words)
    const phrases = [];
    for (let i = 0; i < words.length - 2; i++) {
      phrases.push(words.slice(i, i + 3).join(' '));
    }

    const uniquePhrases = new Set(phrases);
    const phraseRepetitionRatio = 1 - (uniquePhrases.size / phrases.length);

    return {
      passed: uniqueRatio >= this.config.minUniqueRatio &&
               consecutiveRepeats < words.length * 0.1,
      uniqueRatio,
      consecutiveRepeats,
      phraseRepetitionRatio
    };
  }

  /**
   * Basic coherence check
   * @private
   */
  _checkCoherence(text) {
    // Very basic coherence checks
    const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 0);

    // Check for reasonable sentence structure
    const hasCapitalStart = sentences.some(s => /^[A-Z]/.test(s.trim()));
    const hasPunctuation = /[.!?]$/.test(text.trim());
    const avgSentenceLength = sentences.length > 0
      ? text.length / sentences.length
      : 0;

    // Check for random character sequences (same character repeated)
    // This detects actual patterns like "aaaaabbbbbccccc" not normal words
    const hasRandomChars = /(.)\1{9,}/.test(text.replace(/\s/g, ''));

    return {
      passed: sentences.length > 0 &&
               sentences.length <= 10 &&
               avgSentenceLength >= 10 &&
               avgSentenceLength <= 300 &&
               !hasRandomChars,
      sentenceCount: sentences.length,
      avgSentenceLength,
      hasCapitalStart,
      hasPunctuation,
      hasRandomChars
    };
  }

  /**
   * Calculate overall quality rating
   * @private
   */
  _calculateQuality(text, details) {
    // Determine quality tier
    if (details.length.wordCount < 10) {
      return 'low';
    }

    if (details.repetition.uniqueRatio > 0.7 &&
        details.coherence.sentenceCount >= 2) {
      return 'high';
    }

    if (details.repetition.uniqueRatio > 0.5 &&
        details.coherence.sentenceCount >= 1) {
      return 'good';
    }

    return 'medium';
  }

  /**
   * Calculate numeric score
   * @private
   */
  _calculateScore(details) {
    let score = 0;

    // Length score (0-30 points)
    const idealLength = 100; // words
    const lengthScore = 30 * (1 - Math.abs(details.length.wordCount - idealLength) / idealLength);
    score += Math.max(0, Math.min(30, lengthScore));

    // Uniqueness score (0-40 points)
    const uniquenessScore = 40 * details.repetition.uniqueRatio;
    score += uniquenessScore;

    // Coherence score (0-30 points)
    let coherenceScore = 0;
    if (details.coherence.passed) coherenceScore += 15;
    if (details.coherence.hasCapitalStart) coherenceScore += 5;
    if (details.coherence.hasPunctuation) coherenceScore += 5;
    if (details.coherence.sentenceCount >= 2) coherenceScore += 5;
    score += coherenceScore;

    return Math.round(score);
  }

  /**
   * Track a failure by reason
   * @private
   */
  _trackFailure(reason) {
    this.metrics.failedValidations++;
    this.metrics.failuresByReason[reason] = (this.metrics.failuresByReason[reason] || 0) + 1;
  }

  /**
   * Get validation metrics
   */
  getMetrics() {
    return {
      ...this.metrics,
      passRate: this.metrics.totalValidations > 0
        ? this.metrics.passedValidations / this.metrics.totalValidations
        : 0
    };
  }

  /**
   * Reset metrics
   */
  resetMetrics() {
    this.metrics = {
      totalValidations: 0,
      passedValidations: 0,
      failedValidations: 0,
      failuresByReason: {}
    };
  }

  /**
   * Update configuration
   */
  updateConfig(options) {
    Object.assign(this.config, options);
  }
}

/**
 * Default quality validator instance
 */
export const defaultQualityValidator = new QualityValidator();

export default QualityValidator;
